+}
+.topup-opt:hover::before { opacity: 1; }
+.topup-opt.sel {
+  border-color: var(--gold);
+  background: rgba(245,197,24,.05);
+  box-shadow: 0 0 24px rgba(245,197,24,.12);
+}
+.topup-opt.sel::before { opacity: 1; }
+
+/* Featured package */
+.topup-featured {
+  border-color: rgba(245,197,24,.35) !important;
+  background: linear-gradient(145deg, #1c1800, #141000) !important;
+}
+.topup-featured:hover {
+  border-color: var(--gold) !important;
+  box-shadow: 0 8px 32px rgba(245,197,24,.18) !important;
+}
