commits.content:
/* ==============================================
   components.css — Game, Cards, Result Modal
   ============================================== */

/* ---- GAME SCREEN ---- */
#game-screen { display: none; min-height: 100vh; }

.game-hdr {
  display: flex; align-items: center; justify-content: space-between;
  padding: 80px 36px 20px;
  border-bottom: 1px solid #1c1c1c;
}
.g-deck-info { display: flex; align-items: center; gap: 12px; }
.g-deck-ico  { width: 42px; height: 42px; border-radius: 10px; display: flex; align-items: center; justify-content: center; font-size: 1.3rem; }
.g-nm        { font-weight: 700; }
.g-rm        { color: var(--text2); font-size: .82rem; display: flex; align-items: center; gap: 5px; margin-top: 2px; }
.g-credit    { color: var(--gold); font-weight: 700; font-size: 1rem; display: flex; align-items: center; gap: 7px; }

.table-area  { position: relative; min-height: calc(100vh - 200px); display: flex; flex-direction: column; align-items: center; justify-content: flex-start; padding: 24px 16px 80px; }
.cards-wrap  {
  position: relative;
  width: min(900px, 96vw);
  min-height: 500px;
  margin: 0 auto;
}

/* ---- CARDS ---- */
.crd {
  position: absolute; width: 96px; height: 138px;
  border-radius: 12px; cursor: pointer;
  transition: all .28s cubic-bezier(.23,1,.32,1);
  display: flex; align-items: center; justify-content: center;
  user-select: none; transform-origin: center bottom;
  background: repeating-linear-gradient(45deg, #1a0505, #1a0505 4px, #210707 4px, #210707 8px);
  border: 1.5px solid #3a0808;
  box-shadow: 3px 5px 16px rgba(0,0,0,.7), inset 0 1px 0 rgba(255,255,255,.04);
}

/* ---- ไพ่ขนาดเล็กสำหรับมือถือ ---- */
.crd-sm {
  width: 72px !important;
  height: 104px !important;
  border-radius: 9px !important;
}
.crd-sm .crd-back {
  width: 56px !important;
  height: 86px !important;
  font-size: 1.4rem !important;
}

/* .crd:not(.revealed):not(.flipping):hover {
  transform: translateY(-14px) scale(1.07) !important;
  border-color: var(--red);
  box-shadow: 0 22px 44px rgba(229,9,20,.28), 0 0 0 1px var(--red);
  z-index: 60 !important;
} */
.crd-back {
  width: 76px; height: 116px; border-radius: 8px;
  display: flex; align-items: center; justify-content: center;
  font-size: 1.9rem; color: var(--red); opacity: .4;
  background: linear-gradient(135deg, #1a0505, #2d0808);
  border: 1px solid rgba(229,9,20,.18);
}
.crd.flipping { animation: flip .55s ease forwards; pointer-events: none; z-index: 100 !important; }
@keyframes flip {
  0%   { transform: rotateY(0) scale(1); }
  50%  { transform: rotateY(90deg) scale(1.1); }
  100% { transform: rotateY(0) scale(1); }
}
.crd.revealed {
  background: linear-gradient(145deg, #200000, #0c0000);
  border-color: var(--red);
  box-shadow: 0 0 28px rgba(229,9,20,.25);
  cursor: default; pointer-events: none;
}
.crd-revealed-inner {
  display: flex; flex-direction: column; align-items: center; justify-content: center;
  text-align: center; width: 100%; height: 100%; padding: 8px; gap: 4px;
}
.crd-cat { font-size: .6rem; color: var(--red); font-weight: 700; letter-spacing: 1px; }
.crd-txt { font-size: .67rem; color: var(--text2); line-height: 1.3; }

.cost-hint {
  text-align: center; color: var(--text2); font-size: .88rem; margin-top: 18px;
  display: flex; align-items: center; justify-content: center; gap: 7px;
}
.cost-hint .hl { color: var(--gold); font-weight: 700; }

/* ---- RESULT MODAL ---- */
.overlay { position: fixed; inset: 0; background: rgba(0,0,0,.88); z-index: 500; display: none; align-items: center; justify-content: center; backdrop-filter: blur(7px); }
.overlay.show { display: flex; }

.res-card {
  background: linear-gradient(145deg, #1c0404, #0d0000);
  border: 1px solid var(--red2); border-radius: 20px;
  padding: 44px 44px 36px; max-width: 460px; width: 90%;
  text-align: center; position: relative;
  box-shadow: 0 0 80px rgba(229,9,20,.28), 0 0 180px rgba(229,9,20,.08);
  animation: slideUp .38s cubic-bezier(.23,1,.32,1);
}
.res-card::before {
  content: ""; position: absolute; top: 0; left: 0; right: 0; height: 2.5px;
  background: linear-gradient(90deg, transparent, var(--red), transparent);
  border-radius: 20px 20px 0 0;
}
@keyframes slideUp {
  from { transform: translateY(36px) scale(.95); opacity: 0; }
  to   { transform: translateY(0) scale(1);     opacity: 1; }
}
.res-deck-lbl { font-size: .72rem; letter-spacing: 3px; color: var(--text3); text-transform: uppercase; margin-bottom: 12px; display: flex; align-items: center; gap: 6px; justify-content: center; }
.res-ico-wrap { width: 70px; height: 70px; border-radius: 50%; display: flex; align-items: center; justify-content: center; margin: 0 auto 14px; font-size: 1.9rem; }
.res-cat  { font-family: "Kanit", sans-serif; font-weight: 800; font-size: 1rem; color: var(--red); letter-spacing: 4px; margin-bottom: 14px; }
.res-txt  { font-size: 1.5rem; font-weight: 700; line-height: 1.4; margin-bottom: 28px; }
.res-acts { display: flex; gap: 10px; justify-content: center; }

.btn-close-r {
  background: transparent; color: var(--text2); border: 1px solid #333;
  padding: 11px 22px; border-radius: 8px;
  font-family: "Kanit", sans-serif; cursor: pointer; transition: .2s;
  display: flex; align-items: center; gap: 6px;
}
.btn-close-r:hover { border-color: #555; color: #fff; }

.btn-next {
  background: var(--red); color: #fff; border: none;
  padding: 11px 28px; border-radius: 8px;
  font-family: "Kanit", sans-serif; font-weight: 700; font-size: .95rem;
  cursor: pointer; transition: .2s;
  display: flex; align-items: center; gap: 7px;
}
.btn-next:hover { background: var(--red3); transform: translateY(-2px); }

/* ---- RESPONSIVE ---- */
@media (max-width: 580px) {
  .game-hdr { padding: 80px 16px 18px; }
  .res-card { padding: 32px 24px 28px; }
  .res-txt  { font-size: 1.25rem; }
}

/* ============================================
   TOP-UP MODAL
   ============================================ */
.modal-box {
  background: linear-gradient(145deg, #181818, #111);
  border: 1px solid #282828;
  border-radius: 20px;
  padding: 38px;
  max-width: 460px;
  width: 90%;
  position: relative;
}
.modal-x {
  position: absolute; top: 12px; right: 14px;
  background: none; border: none; color: var(--text2);
  cursor: pointer; width: 30px; height: 30px;
  display: flex; align-items: center; justify-content: center;
  border-radius: 50%; transition: .2s; font-size: .95rem;
}
.modal-x:hover { background: #222; color: #fff; }

.modal-ttl {
  font-family: "Kanit", sans-serif;
  font-weight: 900;
  font-size: 1.7rem;
  letter-spacing: 2px;
  margin-bottom: 6px;
  display: flex; align-items: center; gap: 10px;
}
.modal-ttl .r { color: var(--red); }
.modal-sub { color: var(--text2); font-size: .85rem; margin-bottom: 22px; }

.topup-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 10px;
  margin-bottom: 20px;
}
.topup-opt {
  background: #1a1a1a;
  border: 1px solid #262626;
  border-radius: 12px;
  padding: 16px;
  text-align: center;
  cursor: pointer;
  transition: .2s;
}
.topup-opt:hover { border-color: var(--gold); box-shadow: 0 0 18px rgba(245,197,24,.08); }
.topup-opt.sel   { border-color: var(--gold); background: rgba(245,197,24,.04); }

.topup-opt .coins {
  font-size: 1.1rem; font-weight: 700; color: var(--gold);
  display: flex; align-items: center; gap: 6px; justify-content: center;
}
.topup-opt .price { font-size: .8rem; color: var(--text2); margin-top: 4px; }
.topup-opt .bonus {
  font-size: .72rem; color: #4caf50; font-weight: 600; margin-top: 3px;
  display: flex; align-items: center; gap: 4px; justify-content: center;
}

.coming-banner {
  background: rgba(229,9,20,.06);
  border: 1px dashed rgba(229,9,20,.25);
  border-radius: 10px;
  padding: 12px 14px;
  font-size: .82rem;
  color: var(--text2);
  display: flex; flex-direction: column; align-items: center; gap: 5px; text-align: center;
}
.coming-banner strong { color: var(--red); display: flex; align-items: center; gap: 6px; }

.btn-free {
  width: 100%; padding: 13px; margin-top: 14px;
  background: var(--red); color: #fff; border: none;
  border-radius: 8px;
  font-family: "Kanit", sans-serif; font-weight: 700; font-size: 1rem;
  cursor: pointer; transition: .2s;
  display: flex; align-items: center; justify-content: center; gap: 8px;
}
.btn-free:hover { background: var(--red3); }

@media (max-width: 580px) {
  .topup-grid { grid-template-columns: 1fr; }
  .modal-box  { padding: 28px 20px; }
}

/* ============================================
   LAYOUT TOGGLE (scatter / stack)
   ============================================ */
.layout-toggle {
  display: flex;
  background: #111;
  border: 1px solid #2a2a2a;
  border-radius: 8px;
  padding: 3px;
  gap: 2px;
}
.lt-btn {
  background: transparent;
  border: none;
  color: var(--text3);
  width: 32px; height: 32px;
  border-radius: 6px;
  cursor: pointer;
  display: flex; align-items: center; justify-content: center;
  font-size: .9rem;
  transition: all .2s;
}
.lt-btn:hover { color: var(--text2); background: #1a1a1a; }
.lt-btn.act   { background: var(--red); color: #fff; }

/* ============================================
   DISCARD LABEL & ZONE (ใช้ร่วมกันทั้ง scatter & stack)
   ============================================ */
.discard-label {
  font-size: .72rem;
  color: var(--text3);
  letter-spacing: 2px;
  text-transform: uppercase;
  margin-bottom: 6px;
  display: flex;
  align-items: center;
  gap: 6px;
}

.discard-zone {
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
  justify-content: center;
  padding: 8px 0 4px;
  min-height: 60px;
}

/* ============================================
   SCATTER MODE — discard section ใต้โต๊ะ
   ============================================ */
.discard-section {
  width: min(900px, 96vw);
  margin: 20px auto 0;
  padding: 16px;
  border-top: 1px solid #1c1c1c;
}

/* ============================================
   CARD ที่เปิดแล้ว — เล็กลงใน discard zone
   ============================================ */
.crd-discarded {
  position: relative !important;
  width: 56px !important;
  height: 80px !important;
  border-radius: 7px !important;
  cursor: default !important;
  pointer-events: none;
  flex-shrink: 0;
  left: auto !important;
  top: auto !important;
}
.crd-discarded .crd-revealed-inner { padding: 4px; gap: 2px; }
.crd-discarded .crd-cat { font-size: .5rem; letter-spacing: .5px; }
.crd-discarded .crd-txt { font-size: .52rem; line-height: 1.2; }

/* ============================================
   STACK MODE LAYOUT
   ============================================ */
.stack-layout {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 28px;
  padding: 16px;
  width: 100%;
}

.stack-section.stack-center {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 14px;
}

.stack-section { width: 100%; }

.stack-pile-wrap {
  position: relative;
  width: 180px;
  height: 240px;
}

.stack-crd {
  width: 170px !important;
  height: 225px !important;
}

.stack-count {
  font-size: .85rem;
  color: var(--text2);
  text-align: center;
  letter-spacing: 1px;
}

.stack-pile {
  position: relative;
  width: 96px;
  height: 138px;
  margin: 0 auto 24px;
  cursor: pointer;
}
.stack-pile .crd {
  position: absolute !important;
  left: 0 !important; top: 0 !important;
  transition: transform .3s cubic-bezier(.23,1,.32,1) !important;
}

.discard-area {
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
  padding: 12px 0 4px;
  max-width: min(900px, 96vw);
  min-height: 40px;
}

/* Pulse animation */
@keyframes pulse-card {
  0%, 100% { box-shadow: 0 0 22px var(--glow), 3px 6px 18px rgba(0,0,0,.8); }
  50%       { box-shadow: 0 0 44px rgba(229,9,20,.75), 3px 6px 18px rgba(0,0,0,.8); }
}
